+import { MutableRefObject, useEffect, useMemo, useState } from "react";
+import {
+  MathUtils,
+  NearestFilter,
+  NoToneMapping,
+  PerspectiveCamera,
+  RGBAFormat,
+  sRGBEncoding,
+  Vector2,
+  WebGLRenderer,
+  WebGLRenderTarget,
+} from "three";
+import { useThree } from "@react-three/fiber";
+import { useEnvironment } from "../../../layers/Environment";
+
+type Photography = {
+  resolution: Vector2;
+  aspect: Vector2;
+  takePicture: () => void;
+  target: WebGLRenderTarget;
+  fov: number;
+};
+
+export const usePhotography = (
+  cam: MutableRefObject<PerspectiveCamera | undefined>,
+  open: boolean
+): Photography => {
+  const { device } = useEnvironment();
+  const { scene } = useThree();
+
+  const [fov, setFov] = useState(50);
+  useEffect(() => setFov(50), [open]);
+  const resolution = useMemo(
+    () => new Vector2(3, 2).normalize().multiplyScalar(2186),
+    []
+  );
+  const aspect = useMemo(() => resolution.clone().normalize(), [resolution]);
+  const target = useMemo(
+    () =>
+      new WebGLRenderTarget(resolution.x, resolution.y, {
+        stencilBuffer: true, // text boxes look strange without this idk man
+        minFilter: NearestFilter,
+        magFilter: NearestFilter,
+        format: RGBAFormat,
+      }),
+    [resolution]
+  );
+  const renderer = useMemo(() => {
+    const r = new WebGLRenderer({
+      preserveDrawingBuffer: true,
+      precision: "highp",
+      antialias: true,
+    });
+    r.physicallyCorrectLights = true;
+    r.toneMapping = NoToneMapping;
+    r.outputEncoding = sRGBEncoding;
+    return r;
+  }, []);
+
+  useEffect(() => {
+    renderer.setPixelRatio(device.desktop ? 2 : 1); // could be 3, just really fat
+    renderer.setSize(target.width, target.height);
+  }, [device.desktop, target.width, target.height, renderer]);
+
+  useEffect(() => {
+    // increase/decrease fov on scroll
+    const onScroll = (e: WheelEvent) => {
+      if (!cam.current) return;
+      const fov = MathUtils.clamp(cam.current.fov + e.deltaY * 0.05, 10, 75);
+      setFov(fov);
+    };
+    window.addEventListener("wheel", onScroll);
+    return () => window.removeEventListener("wheel", onScroll);
+  }, [cam]);
+
+  const takePicture = () => {
+    if (!cam.current) return;
+
+    document.body.append(renderer.domElement);
+    cam.current.aspect = aspect.x / aspect.y;
+
+    renderer.render(scene, cam.current);
+
+    const link = document.createElement("a");
+    const today = new Date();
+    const name =
+      document.title +
+      " - www.muse.place" +
+      window.location.pathname +
+      " - " +
+      today.toLocaleDateString("en-US") +
+      " " +
+      today.getHours() +
+      ":" +
+      today.getMinutes();
+
+    link.download = `${name}.jpg`;
+    link.href = renderer.domElement.toDataURL("image/jpeg");
+    link.click();
+
+    link.remove();
+    document.body.removeChild(renderer.domElement);
+  };
+
+  return { resolution, aspect, takePicture, target, fov };
+};

@@ -0,0 +1,59 @@
+import { MutableRefObject, RefObject, useEffect, useMemo, useRef } from "react";
+import { useLimitedFrame } from "../../../logic";
+import {
+  Group,
+  Mesh,
+  PerspectiveCamera,
+  Quaternion,
+  Vector3,
+  WebGLRenderTarget,
+} from "three";
+import { useEnvironment } from "../../../layers/Environment";
+import { useThree } from "@react-three/fiber";
+
+export const useRendering = (
+  ENABLED: boolean,
+  cam: MutableRefObject<PerspectiveCamera | undefined>,
+  group: RefObject<Group>,
+  mesh: RefObject<Mesh>,
+  target: WebGLRenderTarget
+) => {
+  const { paused } = useEnvironment();
+  const { scene } = useThree();
+
+  const dummy = useMemo(() => new Vector3(), []);
+  const qummy = useMemo(() => new Quaternion(), []);
+
+  // prep render the camera until first pause to compile materials in advance rather than first time tool is enabled
+  const prepRendering = useRef(true);
+  useEffect(() => {
+    if (!paused) prepRendering.current = false;
+  }, [paused]);
+  useLimitedFrame(1 / 4, (state) => {
+    if (ENABLED || !prepRendering.current || !cam.current) return; // don't double render
+    state.gl.autoClear = true;
+    state.gl.setRenderTarget(target);
+    state.gl.render(scene, cam.current);
+    state.gl.setRenderTarget(null);
+    state.gl.autoClear = false;
+  });
+
+  useLimitedFrame(24, (state) => {
+    if (!cam.current || !mesh.current || !group.current || !ENABLED || !open)
+      return;
+
+    // move mesh to camera's position
+    mesh.current.getWorldPosition(dummy);
+    mesh.current.getWorldQuaternion(qummy);
+    cam.current.position.set(0, 0, 0.5).applyQuaternion(qummy); // move back 0.5m
+    cam.current.position.add(dummy);
+    cam.current.rotation.setFromQuaternion(qummy);
+
+    // render to camera viewfinder
+    state.gl.autoClear = true;
+    state.gl.setRenderTarget(target);
+    state.gl.render(scene, cam.current);
+    state.gl.setRenderTarget(null);
+    state.gl.autoClear = false;
+  });
+};

